const.example:
const PI = 3.14159;
const list = [1, 2];
list.push(3); // OK, the array contents can change

function.example:
function add(a, b) {
  return a + b;
}
console.log(add(2, 3)); // 5

else if.example:
if (score >= 90) {
  console.log('A');
} else if (score >= 80) {
  console.log('B');
} else {
  console.log('C');
}

for...in.example:
const obj = { a: 1, b: 2 };
for (const key in obj) {
  console.log(key, obj[key]);
}

do...while.example:
let n = 0;
do {
  console.log(n);
  n++;
} while (n < 3);

switch.example:
switch (day) {
  case 'Mon':
    console.log('Start of week');
    break;
  default:
    console.log('Another day');
}

break.example:
for (let i = 0; i < 10; i++) {
  if (i === 3) break;
  console.log(i);
}

continue.example:
for (let i = 0; i < 5; i++) {
  if (i % 2 === 0) continue;
  console.log(i); // 1, 3
}

try.example:
try {
  JSON.parse('not json');
} catch (err) {
  console.log('Invalid JSON:', err.message);
}

throw.example:
function check(age) {
  if (age < 0) throw new Error('Age cannot be negative');
}

class.example:
class Point {
  constructor(x, y) {
    this.x = x;
    this.y = y;
  }
}

extends.example:
class Animal {
  speak() { console.log('...'); }
}
class Dog extends Animal {
  speak() { console.log('Woof!'); }
}

constructor.example:
class Point {
  constructor(x, y) {
    this.x = x;
    this.y = y;
  }
}

super.example:
class Dog extends Animal {
  constructor(name) {
    super(name);
  }
}

static.example:
class MathUtils {
  static square(x) { return x * x; }
}
MathUtils.square(4); // 16

export.example:
export function add(a, b) {
  return a + b;
}

async.example:
async function loadData() {
  const data = await fetchData();
  return data;
}

await.example:
async function run() {
  const result = await delay(100);
  console.log(result);
}

instanceof.example:
class Dog {}
const d = new Dog();
console.log(d instanceof Dog); // true
